SELECT [AnalisiCredito-step1-datiSaldoClienti].No_ AS CodiceCliente, [AnalisiCredito-step1-datiSaldoClienti].[Purchase Group], [AnalisiCredito-step1-datiSaldoClienti].Name, [AnalisiCredito-step1-datiSaldoClienti].[Name 2], [AnalisiCredito-step1-datiSaldoClienti].Address, [AnalisiCredito-step1-datiSaldoClienti].[Post Code], [AnalisiCredito-step1-datiSaldoClienti].City, [AnalisiCredito-step1-datiSaldoClienti].County, [AnalisiCredito-step1-datiSaldoClienti].[Country_region Code], [AnalisiCredito-step1-datiSaldoClienti].[VAT Registration No_], [AnalisiCredito-step1-datiSaldoClienti].[Fiscal Code], [AnalisiCredito-step1-datiSaldoClienti].[Payment Method Code], [AnalisiCredito-step1-datiSaldoClienti].[Current Risk], [AnalisiCredito-step1-datiSaldoClienti].[Risk Rating], [AnalisiCredito-step1-datiSaldoClienti].[PM Failure Assigned Score], [AnalisiCredito-step1-datiSaldoClienti].DataAggiornamento, [AnalisiCredito-step1-datiSaldoClienti].DataValutazione, [AnalisiCredito-step1-datiSaldoClienti].DataScadenza, [AnalisiCredito-step1-datiSaldoClienti].[Updated Type], [AnalisiCredito-step1-datiSaldoClienti].[Skip Credit Info Update], [AnalisiCredito-step1-datiSaldoClienti].SaldoD, [AnalisiCredito-step0-datiVendite].[Currency Code], [AnalisiCredito-step0-datiVendite].ValueSoldStagione1, [AnalisiCredito-step0-datiVendite].ValueOutstandingStagione1, [AnalisiCredito-step0-datiVendite].ValueSoldStagione2, [AnalisiCredito-step0-datiVendite].ValueOutstandingStagione2, [AnalisiCredito-step0-datiVendite].ValueReturnStagione1, [AnalisiCredito-step0-datiVendite].ValueReturnStagione2
FROM [AnalisiCredito-step1-datiSaldoClienti] INNER JOIN [AnalisiCredito-step0-datiVendite] ON [AnalisiCredito-step1-datiSaldoClienti].No_ = [AnalisiCredito-step0-datiVendite].[Sell-to Customer No_];

